using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

/// <summary>
/// Server-side implementation that provides shipment data directly (no HTTP round-trip).
/// Used during Interactive Server rendering before WebAssembly takes over.
/// </summary>
public class ShipmentServerService : IShipmentService
{
    private static readonly List<Shipment> _shipments =
    [
        new() { Id = 1, TrackingNumber = "TRK-100201", Origin = "New York, NY", Destination = "Los Angeles, CA", Status = ShipmentStatus.InTransit, ShippedDate = DateTime.UtcNow.AddDays(-3), EstimatedDelivery = DateTime.UtcNow.AddDays(2), CustomerEmail = "alice@example.com", Description = "Electronics - Laptop" },
        new() { Id = 2, TrackingNumber = "TRK-100202", Origin = "Chicago, IL", Destination = "Miami, FL", Status = ShipmentStatus.OutForDelivery, ShippedDate = DateTime.UtcNow.AddDays(-5), EstimatedDelivery = DateTime.UtcNow, CustomerEmail = "bob@example.com", Description = "Furniture - Office Chair" },
        new() { Id = 3, TrackingNumber = "TRK-100203", Origin = "Seattle, WA", Destination = "Denver, CO", Status = ShipmentStatus.Pending, ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(4), CustomerEmail = "carol@example.com", Description = "Books - Bulk Order" },
        new() { Id = 4, TrackingNumber = "TRK-100204", Origin = "Houston, TX", Destination = "Boston, MA", Status = ShipmentStatus.Delivered, ShippedDate = DateTime.UtcNow.AddDays(-7), EstimatedDelivery = DateTime.UtcNow.AddDays(-1), CustomerEmail = "dave@example.com", Description = "Medical Supplies" },
        new() { Id = 5, TrackingNumber = "TRK-100205", Origin = "San Francisco, CA", Destination = "Phoenix, AZ", Status = ShipmentStatus.Delayed, ShippedDate = DateTime.UtcNow.AddDays(-4), EstimatedDelivery = DateTime.UtcNow.AddDays(3), CustomerEmail = "eve@example.com", Description = "Automotive Parts" },
        new() { Id = 6, TrackingNumber = "TRK-100206", Origin = "Atlanta, GA", Destination = "Dallas, TX", Status = ShipmentStatus.PickedUp, ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(3), CustomerEmail = "frank@example.com", Description = "Clothing - Retail Shipment" },
    ];

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(_shipments.ToList());
    }

    public Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = _shipments.FirstOrDefault(s =>
            s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = _shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is not null)
        {
            shipment.Status = newStatus;
        }
        return Task.CompletedTask;
    }
}

using ShipmentTracker.Client.Services;
using ShipmentTracker.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (IShipmentService service) =>
        {
            return Results.Ok(await service.GetAllShipmentsAsync());
        });

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
        }).AllowAnonymous();

        group.MapPut("/{id:int}/status", async (int id, ShipmentStatus newStatus, IShipmentService service) =>
        {
            await service.UpdateShipmentStatusAsync(id, newStatus);
            return Results.NoContent();
        });
    }
}

